<script setup lang="ts">import{useI18n}from'vue-i18n';import type{MonitorRecord}from'@/types/monitor';defineProps<{records:MonitorRecord[];selectedId:string|null}>();defineEmits<{select:[id:string]}>();const{t}=useI18n()</script><template><aside class="monitor-list"><p v-if="!records.length">{{t('monitor.empty')}}</p><button v-for="r in [...records].reverse()" :key="r.requestId" :class="{active:r.requestId===selectedId}" @click="$emit('select',r.requestId)"><strong>{{r.model||t('monitor.unknownModel')}}</strong><span>{{r.api.toUpperCase()}} · {{r.route}}</span><small>{{t(`monitor.status.${r.status}`)}}</small></button></aside></template>
